async function createCompleteFormBuilderPage() {
  try {
    console.log('🔄 Creating complete Form Builder page...');

    const existingPage = await prisma.page.findFirst({
      where: {
        OR: [
          { slug: '/en/form-builder' },
          { title: 'Form Builder' }
        ]
      }
    });

    if (existingPage) {
      await prisma.page.update({
        where: { id: existingPage.id },
        data: {
          title: 'Form Builder',
          slug: '/en/form-builder',
          status: 'published',
          isBuilderPage: true,
          builderData: JSON.stringify({
            sections: completeFormBuilderSections,
            metadata: {
              title: 'Form Builder - Build Smart Forms in Minutes | IVAFlow',
              description: 'Create beautiful, intelligent forms with conditional logic, validation rules, and seamless integration—no coding required.',
              keywords: 'form builder, drag and drop forms, conditional logic, form validation, mobile forms'
            }
          }),
          updatedAt: new Date()
        }
      });
    } else {
      await prisma.page.create({
        data: {
          title: 'Form Builder',
          slug: '/en/form-builder',
          status: 'published',
          isBuilderPage: true,
          builderData: JSON.stringify({
            sections: completeFormBuilderSections,
            metadata: {
              title: 'Form Builder - Build Smart Forms in Minutes | IVAFlow',
              description: 'Create beautiful, intelligent forms with conditional logic, validation rules, and seamless integration—no coding required.',
              keywords: 'form builder, drag and drop forms, conditional logic, form validation, mobile forms'
            }
          }),
          createdAt: new Date(),
          updatedAt: new Date()
        }
      });
    }

    console.log('✅ Complete Form Builder page created successfully!');
    console.log(`📊 Added ${completeFormBuilderSections.length} sections to match HTML sample`);
    
  } catch (error) {
    console.error('❌ Error:', error);
  } finally {
    await prisma.$disconnect();
  }
}

createCompleteFormBuilderPage();